SELECT p.ID, (strftime('%Y', 'now') - strftime('%Y', p.Birthday)) - (strftime('%m%d', 'now') < strftime('%m%d', p.Birthday)) AS Age, e.Diagnosis
FROM Patient p
JOIN Examination e ON p.ID = e.ID
WHERE p.ID IN (
    SELECT ID FROM Laboratory WHERE RBC < (SELECT AVG(RBC) FROM Laboratory)
);

